final class WalletService {
    private let keyManager: SecureKeyManaging
    private let keyTag = "com.example.cryptowallet.mainkey"

    init(keyManager: SecureKeyManaging? = nil) {
        if let keyManager = keyManager {
            self.keyManager = keyManager
        } else {
            if SecureEnclaveKeyManager.isAvailable {
                self.keyManager = SecureEnclaveKeyManager()
            } else {
                self.keyManager = SoftwareKeyManager()
            }
        }
    }

    func createWallet() throws -> WalletAddress {
        let publicKey = try keyManager.generateKeyPair(tag: keyTag)
        return WalletAddress(value: Self.address(from: publicKey))
    }

    func currentAddress() throws -> WalletAddress {
        let publicKey = try keyManager.publicKeyData(tag: keyTag)
        return WalletAddress(value: Self.address(from: publicKey))
    }

    func sign(transaction: BlockchainTransaction) throws -> SignedTransaction {
        let payload = try transaction.signingPayload()
        let signature = try keyManager.sign(data: payload, tag: keyTag)
        let publicKey = try keyManager.publicKeyData(tag: keyTag)
        return SignedTransaction(rawTransaction: payload, signature: signature, publicKey: publicKey)
    }

    private static func address(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

