final class BlockchainAPI {
    private let baseURL: URL
    private let session: URLSession

    init(baseURL: URL, session: URLSession = .shared) {
        self.baseURL = baseURL
        self.session = session
    }

    func broadcast(transaction: SignedTransaction) async throws -> String {
        let url = baseURL.appendingPathComponent("transactions/broadcast")
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let body = try JSONEncoder().encode(transaction)
        request.httpBody = body

        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw WalletError.networkError
        }

        guard let result = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let txId = result["txId"] as? String else {
            throw WalletError.invalidResponse
        }

        return txId
    }

    func fetchBalance(address: String) async throws -> Decimal {
        var components = URLComponents(url: baseURL.appendingPathComponent("address/balance"), resolvingAgainstBaseURL: false)
        components?.queryItems = [URLQueryItem(name: "address", value: address)]

        guard let url = components?.url else {
            throw WalletError.networkError
        }

        let (data, response) = try await session.data(from: url)
        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw WalletError.networkError
        }

        guard let result = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let balanceString = result["balance"] as? String,
              let balance = Decimal(string: balanceString) else {
            throw WalletError.invalidResponse
        }

        return balance
    }
}

