final class WalletViewModel: ObservableObject {
    @Published var address: String = ""
    @Published var balance: String = "0"
    @Published var status: String = ""

    private let walletService: WalletService
    private let api: BlockchainAPI

    init(
        walletService: WalletService = WalletService(),
        api: BlockchainAPI = BlockchainAPI(baseURL: URL(string: "https://api.example-blockchain.com")!)
    ) {
        self.walletService = walletService
        self.api = api
    }

    func setupWallet() {
        do {
            let wallet: WalletAddress
            if let existing = try? walletService.currentAddress() {
                wallet = existing
            } else {
                wallet = try walletService.createWallet()
            }
            address = wallet.value
            status = "Wallet ready"
        } catch {
            status = "Failed to setup wallet"
        }
    }

    func refreshBalance() async {
        do {
            let value = try await api.fetchBalance(address: address)
            balance = NSDecimalNumber(decimal: value).stringValue
            status = "Balance updated"
        } catch {
            status = "Failed to load balance"
        }
    }

    func send(to recipient: String, amount: Decimal) async {
        do {
            let tx = BlockchainTransaction(
                from: address,
                to: recipient,
                amount: amount,
                nonce: UInt64(Date().timeIntervalSince1970),
                chainId: "mainnet",
                payload: nil
            )
            let signed = try walletService.sign(transaction: tx)
            let txId = try await api.broadcast(transaction: signed)
            status = "Sent: \(txId)"
        } catch {
            status = "Transaction failed"
        }
    }
}